1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	  contractCount: number;
11	}
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	const BLOCK_PRICE_FOR_3_ALIKE = 60;
22	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
23	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
24	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
25	const FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER = 0.85;
26	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
27	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const FOLLOW_UP_CONTRACT_MIN_COUNT = 1;
30	
31	const roundToCents = (amount: number): number => Math.round(amount * 100) / 100;
32	
33	const PROCESSING_FEE = 5;
34	
35	const calculateItemCosts = (items: Item[]): number => {
36	  const nonCursedCountsByType: Record<string, number> = {};
37	  let cursedCost = 0;
38	  let enchantmentSurcharge = 0;
39	
40	  for (const item of items) {
41	    const itemBasePremium = BASE_PREMIUMS[item.type];
42	    if (item.cursed) {
43	      cursedCost += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
44	    } else {
45	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
46	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
47	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
48	      }
49	    }
50	  }
51	
52	  let nonCursedCost = 0;
53	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
54	    if (count === 3) {
55	      nonCursedCost += BLOCK_PRICE_FOR_3_ALIKE;
56	    } else {
57	      nonCursedCost += count * BASE_PREMIUMS[type];
58	    }
59	  }
60	
61	  return cursedCost + nonCursedCost + enchantmentSurcharge;
62	};
63	
64	export function generateQuote(items: Item[], customer: Customer): { basePremium: number; premium: number; items: Item[] } {
65	  const followUpMultiplier = customer.contractCount >= FOLLOW_UP_CONTRACT_MIN_COUNT ? FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER : 1;
66	  const loyaltyMultiplier = customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS ? LOYALTY_DISCOUNT_MULTIPLIER : 1;
67	  const basePremium = roundToCents(calculateItemCosts(items) * FIRST_INSURANCE_SURCHARGE_MULTIPLIER * followUpMultiplier * loyaltyMultiplier);
68	  return { basePremium, premium: Math.ceil(basePremium + PROCESSING_FEE), items };
69	}
70	
71	const DEDUCTIBLE = 100;
72	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
73	const HIGH_ENCHANTMENT_PAYOUT_MULTIPLIER = 0.5;
74	
75	interface Policy {
76	  basePremium: number;
77	  premium: number;
78	  items: Item[];
79	}
80	
81	interface Damage {
82	  itemType: string;
83	  amount: number;
84	}
85	
86	interface Incident {
87	  cause: string;
88	  damages: Damage[];
89	}
90	
91	const applyEnchantmentReduction = (amount: number, enchantment: number): number =>
92	  enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
93	    ? amount * HIGH_ENCHANTMENT_PAYOUT_MULTIPLIER
94	    : amount;
95	
96	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
97	  const damage = incident.damages[0];
98	  const item = policy.items.find((i) => i.type === damage.itemType);
99	  const enchantment = item?.enchantment ?? 0;
100	  const effectiveDamage = applyEnchantmentReduction(damage.amount, enchantment);
101	  const payout = Math.max(0, effectiveDamage - DEDUCTIBLE);
102	  return { payout, remainingCap: 0 };
103	}
